import Hero from '@/components/Hero';
import Project from '@/types/Project';
import dateFormater from '@/utils/dateFormater';

export default async function Home() {
  async function fetchData() {
    const projectsResponse = await fetch(`${process.env.API_URL}/projects`);
    const experiencesResponse = await fetch(
      `${process.env.API_URL}/experiences`
    );

    const { data: projectsData } = await projectsResponse.json();
    const { data: experiencesData } = await experiencesResponse.json();

    return { projectsData, experiencesData };
  }
  const { projectsData, experiencesData } = await fetchData();
  console.log(projectsData);
  const lastExperience: {
    title: string;
    description: string;
    startedAt: Date;
    finishedAt: Date;
  } = experiencesData.splice(-1)[0];
  return (
    <main className="h-screen">
      <Hero />
      {projectsData &&
        projectsData.map((project: Project) => (
          <div className="p-8 text-white" key={project.id}>
            <h2>{project.projectName}</h2>
            <p>{project.slug}</p>
            <p>{project.description}</p>
            <a href={project.projectLink} target="_blank">
              Ver projeto.
            </a>
            <br />
            <a href={project.githubLink} target="_blank">
              Ver no github
            </a>
          </div>
        ))}

      {lastExperience && (
        <div className="p-8 text-white" key={lastExperience.title}>
          <h2>{lastExperience.title}</h2>
          <p>{lastExperience.description}</p>
          <p>{dateFormater(lastExperience.startedAt)}- Presente</p>
        </div>
      )}

      {experiencesData &&
        experiencesData.map((experience: any) => (
          <div className="p-8 text-white" key={experience.id}>
            <h2>{experience.title}</h2>
            <p>{experience.description}</p>
            <p>
              {dateFormater(experience.startedAt)} -{' '}
              {dateFormater(experience.finishedAt)}
            </p>
          </div>
        ))}
    </main>
  );
}
